const place = $input.first().json;

function extractCityFromAddress(addr) {
  if (!addr) return null;
  const parts = addr.split(',').map(s => s.trim());
  const CITIES = ['Lisboa','Porto','Cascais','Sintra','Oeiras','Setúbal','Faro','Loulé','Lagoa','Lagos','Portimão','Albufeira','Funchal','Madeira','Ponta Delgada'];
  for (const part of parts) {
    const found = CITIES.find(c => part.includes(c));
    if (found) return found;
  }
  return parts[parts.length - 3] || null;
}

function extractTipo(title, search) {
  const h = `${title} ${search}`.toLowerCase();
  if (h.includes('hotel')) return 'hotel';
  if (h.includes('quinta')) return 'quinta';
  if (h.includes('herdade')) return 'herdade';
  if (h.includes('edifício') || h.includes('edificio')) return 'prédio';
  if (h.includes('terreno')) return 'terreno';
  if (h.includes('guest house') || h.includes('guesthouse')) return 'hotel';
  return 'comercial';
}

const placeId = place.placeId ?? place.id ?? String(Date.now());

return [{ json: {
  source: 'google_maps',
  source_listing_id: String(placeId),
  source_url: place.url ?? place.website ?? null,
  nome: place.title ?? 'Proprietário Google Maps',
  tipo_ativo: extractTipo(place.title ?? '', place.searchString ?? ''),
  localizacao: place.address ?? null,
  cidade: extractCityFromAddress(place.address),
  contacto: place.phone ?? null,
  owner_type: 'empresa',
  urgency: 'unknown',
  status: 'new',
  raw_data: {
    rating: place.totalScore,
    reviews: place.reviewsCount,
    category: place.categoryName,
    website: place.website,
  }
}}];
